void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    /*  Floyd‑Warshall: path[i][j] = min(path[i][j], path[i][k] + path[k][j])  */
    /*  Parallelise the inner two loops across many threads, keeping the outer
       k‑loop serial (required for correctness).  */
    #pragma omp parallel for schedule(static) collapse(2) \
        shared(n, path) private(omp_in_deps)
    for (int k = 0; k < n; ++k) {
        for (int i = 0; i < n; ++i) {
            int* row_i = path[i].data();
            int aik = row_i[k];
            for (int j = 0; j < n; ++j) {
                int val = aik + path[k][j];
                if (val < row_i[j]) row_i[j] = val;
            }
        }
    }
}
