/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Parallelise the outer loop with OpenMP.  The loop is
       embarrassingly parallel – each iteration performs independent
       work.  We also block the inner loop to improve cache reuse
       when n is large.  The block size is chosen so that two blocks
       (~12 kB each) fit comfortably into the L1 cache. */
    const int block = 32;                      // tune to cache size

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; i++)
    {
        double local_tmp = 0.0;
        double local_y   = 0.0;

        const double *Ai = A[i].data();          // row of A
        const double *Bi = B[i].data();          // row of B
        const double *xptr = x.data();           // full vector x

        /* Accumulate products in blocks for better cache utilisation */
        for (int jj = 0; jj < n; jj += block)
        {
            int jend = (jj + block > n) ? n : jj + block;
            for (int j = jj; j < jend; ++j)
            {
                local_tmp += Ai[j] * xptr[j];
                local_y   += Bi[j] * xptr[j];
            }
        }

        /* Store intermediate result */
        tmp[i] = local_tmp;
        y[i]   = alpha * local_tmp + beta * local_y;
    }
}
