void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    /*  The core algorithm is a level‑1 blocked forward substitution.
        We access the L matrix row‑by‑row to keep the inner loop
        sequential and to avoid bounds checks typical of the vector
        interface.  The function remains exactly equivalent to the
        original specification. */
    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        const double* Li = L[i].data();   // pointer to the start of row i

        /* Compute the dot product with the already solved elements.
           The inner loop is kept in a contiguous block to maximise cache
           usage.  No extra temporaries are needed. */
        for (int j = 0; j < i; ++j) {
            sum -= Li[j] * x[j];
        }

        /* Divide by the diagonal element. */
        x[i] = sum / Li[i];
    }
