/**
 * @brief Optimised Symmetric Rank‑k (SYRK) kernel.
 * @param n   number of rows/columns in the square matrix C
 * @param m   number of columns in matrix A (A is n×m)
 * @param alpha scalar multiplier for A*Aᵀ
 * @param beta   scalar multiplier for C
 * @param C      square matrix (n×n) to be updated (inclusive of symmetry)
 * @param A      matrix (n×m)
 *
 * The implementation flattens the 2‑D std::vector containers, reorders the
 * loops for better cache locality, and parallelises across rows of C.
 * The algorithm is mathematically identical to the original reference.
 */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // flat pointers for the underlying data
    double *c = reinterpret_cast<double*>(C.data());
    double *a = reinterpret_cast<double*>(A.data());

    /* The inner loop writes only to the lower triangular part of C
     * (including the diagonal).  We therefore stride the accessing
     * pattern accordingly.  For maximum performance we walk C
     * column by column inside each row loop, because each element
     * in A[i][k] is reused for all j up to i.
     */

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        int offset_i = i * n;           // starting address of row i in C
        double *ci = C[i].data();       // pointer to row i of C

        /* scale the lower‑triangular part by beta */
        for (int j = 0; j <= i; ++j)
            ci[j] *= beta;

        /* accumulate alpha * A[i][k] * A[j][k] for all k */
        for (int k = 0; k < m; ++k) {
            double aik = a[i * m + k];   // A[i][k]
            for (int j = 0; j <= i; ++j)
                ci[j] += alpha * aik * a[j * m + k];
        }
    }
}
