/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Flatten the 2‑D vectors into 1‑D arrays in row‑major order.
       We do this only once per function call so the overhead is negligible. */
    std::vector<double> A_flat; A_flat.reserve(m * m);
    for (int i = 0; i < m; ++i)
        A_flat.insert(A_flat.end(), A[i].begin(), A[i].end());

    std::vector<double> B_flat; B_flat.reserve(m * n);
    for (int i = 0; i < m; ++i)
        B_flat.insert(B_flat.end(), B[i].begin(), B[i].end());

    /* Parallelise the outer two loops. Each iteration over (i,j) is completely
       independent, so we can safely parallelise without any race conditions. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            /* Perform the inner product: sum_{k=i+1}^{m-1} A[k][i] * B[k][j] */
            for (int k = i + 1; k < m; ++k) {
                double a_k_i = A_flat[k * m + i];
                double b_k_j = B_flat[k * n + j];
                sum += a_k_i * b_k_j;
            }
            B_flat[i * n + j] = alpha * sum;
        }
    }

    /* Copy the flattened result back into the original 2‑D vector B. */
    for (int i = 0; i < m; ++i)
        std::copy(B_flat.begin() + i * n,
                  B_flat.begin() + (i + 1) * n,
                  B[i].begin());
}
