/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Compensate for cache‑miss friendliness by extracting row pointers once
    const double *alpha_ptr = &alpha;
    const double *beta_ptr  = &beta;

    /* Parallelise over the outer “i” loop.  
     * Each thread works on disjoint row indices and therefore has no
     * race conditions on the C array because the loop writes to
     * C[i][j] and updates other rows C[k][j] only for k<i.
     * The OpenMP schedule is static to avoid runtime overhead. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i)
    {
        const std::vector<double>& C_row = C[i];
        const std::vector<double>& B_row = B[i];
        const double* A_row = A[i].data();          // pointer to row i of A
        const double A_ii = A_row[i];               // A[i][i]

        for (int j = 0; j < n; ++j)
        {
            const double B_ij = B_row[j];
            double temp2 = 0.0;

            // Unroll inner accumulation over k< i
            for (int k = 0; k < i; ++k)
            {
                // C[k][j] += alpha * B[i][j] * A[i][k];
                C[k][j] += (*alpha_ptr) * B_ij * A_row[k];
                temp2 += B[k][j] * A_row[k];
            }

            // Final update of C[i][j]
            C_row[j] = (*beta_ptr) * C_row[j]
                       + (*alpha_ptr) * B_ij * A_ii
                       + (*alpha_ptr) * temp2;
        }
    }
}
