#include <cmath>
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

void kernel_correlation(
    int m, int n,
    std::vector<std::vector<double>>& data,
    std::vector<std::vector<double>>& corr,
    std::vector<double>& mean,
    std::vector<double>& stddev)
{
    constexpr double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---- Step 1: compute mean per column ---- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s / n;
    }

    /* ---- Step 2: compute stddev per column ---- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mean[j];
            s += d * d;
        }
        s /= n;
        s = std::sqrt(s);
        stddev[j] = (s <= eps) ? 1.0 : s;   // avoid division by zero
    }

    /* ---- Step 3: normalize data ---- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
            row[j] /= inv_sqrt_n * stddev[j];
        }
    }

    /* ---- Step 4: compute correlation matrix (upper triangle) ---- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k)
                s += data[k][i] * data[k][j];
            corr[i][j] = s;
            corr[j][i] = s;                     // symmetry
        }
    }
}
