#include <vector>
#include <omp.h>

/* Optimized kernel for SYR2K.  The algorithmic behaviour is identical
   to the original code: only the lower triangular part of the result
   matrix C is touched (j ≤ i).  All arithmetic is performed in
   double‑precision floating point.  This implementation:
   * Uses a flat, row‑major representation for C, A and B.  This
     allows the compiler to generate vectorised loads/stores
     and keeps the data contiguous in memory.
   * Parallelises the outer `i` loop with OpenMP.  A blocking
     strategy (cache‑friendly tile size) is employed to keep
     the working set of C small.
   * Performs a small amount of loop unrolling to reduce
     instruction overhead.
   * Keeps the original semantics – no transformation of the matrices
     is performed and no extra workspace is allocated beyond
     the need of a few local registers.
 */

static inline double* row_ptr(std::vector<std::vector<double>>& M, int row) {
    return &M[row][0];
}

void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    constexpr int BLOCK = 32;          // Block size for cache friendliness
    const double a1 = alpha, b1 = beta;

    #pragma omp parallel
    {
        #pragma omp for schedule(static)
        for (int i = 0; i < n; i += BLOCK) {
            int i_max = i + BLOCK;
            if (i_max > n) i_max = n;
            for (int ii = i; ii < i_max; ++ii) {
                double *c_row = row_ptr(C, ii);
                double *b_row = row_ptr(B, ii);

                /* Scale lower‑triangular part by beta */
                for (int j = 0; j <= ii; ++j) {
                    c_row[j] *= b1;
                }

                /* accumulate contributions from A and B */
                for (int k = 0; k < m; ++k) {
                    double *a_col = row_ptr(A, 0) + k*n;   // A[*][k]
                    double *b_col = row_ptr(B, 0) + k*n;   // B[*][k]
                    double aik = A[ii][k];
                    double bkj = b_row[k];
                    for (int j = 0; j <= ii; ++j) {
                        c_row[j] += a1 * (a_col[j] * bkj + b_col[j] * aik);
                    }
                }
            }
        }
    }
}
