/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {
    // Allocate temporary storage once (avoids per‑loop allocation)
    std::vector<double> z(n);

    // Work with raw pointers for speed
    const double* rptr = r.data();
          double* yptr = y.data();
          double* zptr = z.data();

    yptr[0] = -rptr[0];
    double beta  = 1.0;
    double alpha = -rptr[0];

    /* The algorithm is inherently serial: each iteration depends on
       the previous ones.  Nevertheless, the inner loops are short
       so the cost of an OpenMP task overhead would outweigh any
       benefit.  We keep the code fully serial but perform hand‑rolled
       inner‑loop optimisations. */
    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        const double* rkptr = rptr + k - 1;
        for (int i = 0; i < k; ++i, --rkptr, ++yptr) {
            sum += (*rkptr) * (*yptr);
        }

        alpha = -(rptr[k] + sum) / beta;

