void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    auto match = [](int b1, int b2) -> int { return (b1 + b2 == 3) ? 1 : 0; };

    // Process by increasing diagonal distance (gap)
    for (int d = 1; d < n; ++d) {
        const int max_i = n - d - 1;
        #pragma omp parallel for schedule(static)
        for (int i = 0; i <= max_i; ++i) {
            int j = i + d;
            int best = 0;

            // table[i][j-1]
            best = std::max(best, table[i][j - 1]);

            // table[i+1][j]
            best = std::max(best, table[i + 1][j]);

            // table[i+1][j-1] + match
            if (i + 1 < j) {
                best = std::max(best, table[i + 1][j - 1] + match(seq[i], seq[j]));
            }

            // split at k
            int left, right;
            for (int k = i + 1; k < j; ++k) {
                left  = table[i][k];
                right = table[k + 1][j];
                best = std::max(best, left + right);
            }
            table[i][j] = best;
        }
    }
}
