// Kernel covariance, optimized for speed with GCC O2 + OpenMP.
// Modifies data in-place by subtracting the mean.
// Computes the (symmetric) covariance matrix in cov.
// The interface is preserved exactly.
//
// Author: C++ Performance Engineer
//
void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean) {
    // Flatten the 2‑D data vector to a contiguous array for efficient
    // cache usage.  The outer dimension is the columns (variables),
    // the inner is the rows (samples).  The layout matches the
    // original algorithm: data[row][col].
    std::vector<double> flat_data(m * n);
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat_data[i * m + j] = data[i][j];

    // ---------------------------------------------------------------------
    // 1. Compute column means.
    // ---------------------------------------------------------------------
    std::vector<double> mean_local(m, 0.0);
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += flat_data[i * m + j];
        mean_local[j] = sum / n;
    }

    // Copy to the output vector (preserves original order).
    std::memcpy(mean.data(), mean_local.data(), m * sizeof(double));

    // ---------------------------------------------------------------------
    // 2. Subtract means from data (in-place, column‑wise).
    // ---------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat_data[i * m + j] -= mean_local[j];

    // ---------------------------------------------------------------------
    // 3. Compute covariance matrix (upper‑triangular, then mirror).
    // ---------------------------------------------------------------------
    const double inv_den = 1.0 / (n - 1.0);

    // Temporary buffer for the computed upper triangle.
    std::vector<double> cov_buf(m * m, 0.0);

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            // dot product of column i and j
            for (int k = 0; k < n; ++k) {
                double a = flat_data[k * m + i];
                double b = flat_data[k * m + j];
                sum += a * b;
            }
            double val = sum * inv_den;
            cov_buf[i * m + j] = val;
            cov_buf[j * m + i] = val;  // symmetry
        }
    }

    // Copy the result back to the user-provided covariance vector.
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < m; ++j)
            cov[i][j] = cov_buf[i * m + j];
}
