void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {

    const int team_size = 8;   // number of threads

    // ------------------------------------------------------------------
    // LU decomposition with forward transformation
    // ------------------------------------------------------------------
#pragma omp parallel for num_threads(team_size) schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ai = A[i].data();                  // row i

        /* Compute L sub‑diagonal entries */
        for (int j = 0; j < i; ++j) {
            double w = Ai[j];
            double* Aj = A[j].data();              // row j
            for (int k = 0; k < j; ++k) {
                w -= Ai[k] * Aj[k];
            }
            Ai[j] = w / Aj[j];
        }

        /* Update upper part (U) of the row */
        for (int j = i; j < n; ++j) {
            double w = Ai[j];
            for (int k = 0; k < i; ++k) {
                w -= Ai[k] * A[k][j];
            }
            Ai[j] = w;
        }
    }

    // ------------------------------------------------------------------
    // Forward substitution A * y = b  (A is now L*U)
    // ------------------------------------------------------------------
#pragma omp parallel for num_threads(team_size) schedule(static)
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        double* Ai = A[i].data();
        for (int j = 0; j < i; ++j) {
            w -= Ai[j] * y[j];
        }
        y[i] = w;
    }

    // ------------------------------------------------------------------
    // Backward substitution U * x = y
    // ------------------------------------------------------------------
#pragma omp parallel for num_threads(team_size) schedule(dynamic)
    for (int ii = 0; ii < n; ++ii) {
        int i = n - 1 - ii;                        // loop from n-1 down to 0
        double w = y[i];
        double* Ai = A[i].data();
        for (int j = i + 1; j < n; ++j) {
            w -= Ai[j] * x[j];
        }
        x[i] = w / Ai[i];
    }
}
