void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {

    /* Treat the 2‑D std::vector as an array of pointers to rows.
       This eliminates bounds checks and lets us use OpenMP efficiently. */
    double** a = new double*[m];
    double** r = new double*[n];
    double** q = new double*[m];
    for (int i = 0; i < m; ++i) a[i] = A[i].data();
    for (int i = 0; i < n; ++i) r[i] = R[i].data();
    for (int i = 0; i < m; ++i) q[i] = Q[i].data();

    /* Main algorithm */
    for (int k = 0; k < n; ++k) {
        /* 1. Compute the norm of the k‑th column */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double v = a[i][k];
            nrm += v * v;
        }
        r[k][k] = std::sqrt(nrm);

        /* 2. Compute the k‑th orthonormal vector */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            q[i][k] = a[i][k] / r[k][k];
        }

        /* 3. Upper triangle and orthogonalisation of remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double dot = 0.0;
#pragma omp parallel for reduction(+:dot) schedule(static)
            for (int i = 0; i < m; ++i) {
                dot += q[i][k] * a[i][j];
            }
            r[k][j] = dot;

#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                a[i][j] -= q[i][k] * dot;
            }
        }
    }

    delete[] a;
    delete[] r;
    delete[] q;
}
