                    double b = B[i][j][k];
                    A[i][j][k] = coef * (B[i+1][j][k] - 2.0 * b + B[i-1][j][k])
                               + coef * (B[i][j+1][k] - 2.0 * b + B[i][j-1][k])
                               + coef * (B[i][j][k+1] - 2.0 * b + B[i][j][k-1])
                               + b;
                }
            }
        }
    }
}
