    // Pre‑compute all constants once, use float for speed
    const float A = static_cast<float>(alpha);
    const float expA = std::expf(A);
    const float exp2A = expA * expA;
    const float expNegA = std::expf(-A);
    const float expNeg2A = expNegA * expNegA;

    const float denom = 1.0f + 2.0f * A * expNegA - expNeg2A;
    const float k = 1.0f - expNegA * (1.0f - expNegA) / denom;

    const float a1 =  k,  a5 =  k;
    const float a2 =  k * expNegA * (A - 1.0f),  a6 =  k * expNegA * (A - 1.0f);
    const float a3 =  k * expNegA * (A + 1.0f),  a7 =  k * expNegA * (A + 1.0f);
    const float a4 = -k * expNeg2A,            a8 = -k * expNeg2A;

    const float b1 = std::powf(2.0f, -A);
    const float b2 = -expNeg2A;
    const float c1 = 1.0f, c2 = 1.0f;

    // ---------- horizontal forward ----------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float in = imgIn[i][j];
            const float y = a1 * in + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            xm1 = in;          ym2 = ym1;          ym1 = y;
        }
    }

    // ---------- horizontal backward ----------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            const float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            xp2 = xp1;            xp1 = imgIn[i][j];
            yp2 = yp1;            yp1 = y;
        }
    }

    // ---------- combine horizontal passes ----------
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);

