/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {

    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 * 0.5;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 * 0.5;
    const double e = 1.0 + mul2;
    const double f = d;

    /* Linearise the 2‑D vectors to improve locality */
    const int N = n;
    const int stride = N;
    double *u_data = new double[N * N];
    double *v_data = new double[N * N];
    /* Flatten p and q only as temporaries; the original
       vectors are not used after this point. */
    for (int i = 0; i < N; ++i)
        std::memcpy(u_data + i * stride, u[i].data(), N * sizeof(double));
    for (int i = 0; i < N; ++i)
        std::memcpy(v_data + i * stride, v[i].data(), N * sizeof(double));

    /* Scratch buffers reused for each i; size (n-1) because
       indices j = 0 .. n-2 are used for the intermediate arrays. */
    std::vector<double> p_local(N - 1);
    std::vector<double> q_local(N - 1);

    for (int t = 1; t <= tsteps; ++t) {

        /* Solve along the i‑direction (columns) */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < N - 1; ++i) {
            const int base = i * stride;
            const int base_prev = (i - 1) * stride;
            const int base_next = (i + 1) * stride;

            /* Forward sweep for v */
            v_data[0 * stride + i] = 1.0;
            p_local[0] = 0.0;
            q_local[0] = v_data[0 * stride + i];

            for (int j = 1; j < N - 1; ++j) {
                const int idx = j * stride + i;
                double denom = a * p_local[j - 1] + b;
                p_local[j] = -c / denom;
                double tmp = -d * u_data[j * stride + i - 1]
                              + (1.0 + 2.0 * d) * u_data[idx]
                              - f * u_data[j * stride + i + 1]
                              - a * q_local[j - 1];
                q_local[j] = tmp / denom;
            }

            v_data[(N - 1) * stride + i] = 1.0;

            /* Backward sweep for v */
            for (int j = N - 2; j >= 1; --j) {
                const int idx = j * stride + i;
                v_data[idx] = p_local[j] * v_data[(j + 1) * stride + i] + q_local[j];
            }
        }

        /* Solve along the j‑direction (rows) */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < N - 1; ++i) {
            const int base = i * stride;
            const int base_prev = (i - 1) * stride;
            const int base_next = (i + 1) * stride;

            /* Forward sweep for u */
            u_data[base + 0] = 1.0;
            p_local[0] = 0.0;
            q_local[0] = u_data[base + 0];

            for (int j = 1; j < N - 1; ++j) {
                const int idx = base + j;
                double denom = d * p_local[j - 1] + e;
                p_local[j] = -f / denom;
                double tmp = -a * v_data[base_prev + j]
                              + (1.0 + 2.0 * a) * v_data[idx]
                              - c * v_data[base_next + j]
                              - d * q_local[j - 1];
                q_local[j] = tmp / denom;
            }

            u_data[base + (N - 1)] = 1.0;

            /* Backward sweep for u */
            for (int j = N - 2; j >= 1; --j) {
                const int idx = base + j;
                u_data[idx] = p_local[j] * u_data[base + j + 1] + q_local[j];
            }
        }
    }

    /* Copy results back to the original 2‑D vectors */
    for (int i = 0; i < N; ++i) {
        std::memcpy(u[i].data(), u_data + i * stride, N * sizeof(double));
        std::memcpy(v[i].data(), v_data + i * stride, N * sizeof(double));
    }

    delete[] u_data;
    delete[] v_data;
}
